INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX285', 'Regenerative Braking', 'E_recov = η·½m(v₁² - v₂²)', 'automotive', 'transportation', 'Automotive');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX286', 'Battery Model', 'V = V_oc - I·R_int', 'automotive', 'transportation', 'Automotive');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX287', 'Lift', 'L = ½ρv²·C_L·A', 'aerospace', 'transportation', 'Aerospace');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX288', 'Drag', 'D = ½ρv²·C_D·A', 'aerospace', 'transportation', 'Aerospace');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX289', 'Thrust', 'F = ṁ·v_e + (p_e - p₀)·A_e', 'aerospace', 'transportation', 'Aerospace');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX290', 'Rocket Equation', 'Δv = v_e·ln(m₀/m_f)', 'aerospace', 'transportation', 'Aerospace');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX291', 'Specific Impulse', 'I_sp = F/(ṁ·g₀)', 'aerospace', 'transportation', 'Aerospace');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX292', 'Mach Number', 'M = v/c', 'aerospace', 'transportation', 'Aerospace');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX293', 'Glide Ratio', 'L/D = C_L/C_D', 'aerospace', 'transportation', 'Aerospace');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX294', 'Orbital Velocity', 'v = √(GM/r)', 'aerospace', 'transportation', 'Aerospace');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX295', 'Hull Resistance', 'R_total = R_f + R_w + R_app', 'marine', 'transportation', 'Marine');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX296', 'Froude Number', 'Fr = v/√(gL)', 'marine', 'transportation', 'Marine');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX297', 'Propeller Thrust', 'T = ρ·n²·D⁴·K_T', 'marine', 'transportation', 'Marine');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX298', 'Black-Scholes PDE', '∂V/∂t + ½σ²S²∂²V/∂S² + rS∂V/∂S - rV = 0', 'derivatives', 'financial', 'Derivatives');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX299', 'Black-Scholes Call', 'C = S·N(d₁) - K·e^{-rT}·N(d₂)', 'derivatives', 'financial', 'Derivatives');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX300', 'd₁ formula', 'd₁ = [ln(S/K) + (r + σ²/2)T]/(σ√T)', 'derivatives', 'financial', 'Derivatives');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX301', 'd₂ formula', 'd₂ = d₁ - σ√T', 'derivatives', 'financial', 'Derivatives');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX302', 'Put-Call Parity', 'C - P = S - K·e^{-rT}', 'derivatives', 'financial', 'Derivatives');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX303', 'Binomial Tree', 'S_u = S·u, S_d = S·d', 'derivatives', 'financial', 'Derivatives');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX304', 'Risk-Neutral Probability', 'p = (e^{rΔt} - d)/(u - d)', 'derivatives', 'financial', 'Derivatives');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX305', 'Delta', 'Δ = ∂V/∂S', 'derivatives', 'financial', 'Derivatives');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX306', 'Gamma', 'Γ = ∂²V/∂S²', 'derivatives', 'financial', 'Derivatives');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX307', 'Vega', 'ν = ∂V/∂σ', 'derivatives', 'financial', 'Derivatives');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX308', 'CAPM', 'E(Rᵢ) = R_f + βᵢ(E(R_m) - R_f)', 'asset', 'financial', 'Asset Pricing');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX309', 'Beta', 'βᵢ = Cov(Rᵢ,R_m)/Var(R_m)', 'asset', 'financial', 'Asset Pricing');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX310', 'APT', 'Rᵢ = E(Rᵢ) + β₁F₁ + β₂F₂ + ... + εᵢ', 'asset', 'financial', 'Asset Pricing');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX311', 'Fama-French 3-Factor', 'Rᵢ - R_f = α + β₁(R_m - R_f) + β₂SMB + β₃HML + ε', 'asset', 'financial', 'Asset Pricing');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX312', 'Sharpe Ratio', 'S = (R_p - R_f)/σ_p', 'asset', 'financial', 'Asset Pricing');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX313', 'Treynor Ratio', 'T = (R_p - R_f)/β_p', 'asset', 'financial', 'Asset Pricing');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX314', 'Jensen''s Alpha', 'α = R_p - [R_f + β_p(R_m - R_f)]', 'asset', 'financial', 'Asset Pricing');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX315', 'Information Ratio', 'IR = α/σ_ε', 'asset', 'financial', 'Asset Pricing');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX316', 'Value at Risk', 'VaRₐ = μ - σ·Φ⁻¹(α)', 'risk', 'financial', 'Risk Management');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX317', 'Conditional VaR', 'CVaR = E[X|X < VaR]', 'risk', 'financial', 'Risk Management');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX318', 'Expected Shortfall', 'ES = (1/(1-α))∫_α¹ VaR_u du', 'risk', 'financial', 'Risk Management');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX319', 'Stress Testing', 'Scenario-based risk assessment', 'risk', 'financial', 'Risk Management');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX320', 'Scenario Analysis', 'What-if analysis', 'risk', 'financial', 'Risk Management');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX321', 'Credit VaR', 'Credit risk metrics', 'risk', 'financial', 'Risk Management');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX322', 'Duration', 'D = - (1/P)(dP/dy)', 'risk', 'financial', 'Risk Management');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX323', 'Convexity', 'C = (1/P)(d²P/dy²)', 'risk', 'financial', 'Risk Management');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX324', 'Markowitz Mean-Variance', 'min σ_p² s.t. E[R_p] = target', 'portfolio', 'financial', 'Portfolio Theory');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX325', 'Efficient Frontier', 'Set of optimal portfolios', 'portfolio', 'financial', 'Portfolio Theory');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX326', 'Capital Market Line', 'E[R_p] = R_f + (E[R_m] - R_f)(σ_p/σ_m)', 'portfolio', 'financial', 'Portfolio Theory');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX327', 'Security Market Line', 'E[Rᵢ] = R_f + βᵢ(E[R_m] - R_f)', 'portfolio', 'financial', 'Portfolio Theory');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX328', 'Diversification', 'σ_p² = Σwᵢ²σᵢ² + ΣΣwᵢwⱼσᵢⱼ', 'portfolio', 'financial', 'Portfolio Theory');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX329', 'Black-Litterman Model', 'E[R] = [(τΣ)^{-1} + PᵀΩ^{-1}P]^{-1}[(τΣ)^{-1}Π + PᵀΩ^{-1}Q]', 'portfolio', 'financial', 'Portfolio Theory');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX330', 'Bond Pricing', 'P = Σ C/(1+y)ᵗ + F/(1+y)ᵀ', 'fixed', 'financial', 'Fixed Income');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX331', 'Yield to Maturity', 'P = Σ C/(1+YTM)ᵗ + F/(1+YTM)ᵀ', 'fixed', 'financial', 'Fixed Income');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX332', 'Spot Rate', 'Zero-coupon yield', 'fixed', 'financial', 'Fixed Income');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX333', 'Forward Rate', '(1+f)ᵗ = (1+s_{t})ᵗ/(1+s_{t-1})ᵗ⁻¹', 'fixed', 'financial', 'Fixed Income');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX334', 'SHA-256 Hash', 'H = SHA-256(message)', 'fintech', 'financial', 'FinTech');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX335', 'Merkle Tree', 'root = H(H(a)||H(b))', 'fintech', 'financial', 'FinTech');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX336', 'Proof of Work', 'H(n||h) < target', 'fintech', 'financial', 'FinTech');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX337', 'Smart Contract Gas', 'gas = Σ opcode_cost', 'fintech', 'financial', 'FinTech');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX338', 'Binary Search', 'T(n) = T(n/2) + O(1) = O(log n)', 'algorithms', 'computerscience', 'Algorithms');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX339', 'Merge Sort', 'T(n) = 2T(n/2) + O(n) = O(n log n)', 'algorithms', 'computerscience', 'Algorithms');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX340', 'Quick Sort', 'T(n) = T(k) + T(n-k-1) + O(n)', 'algorithms', 'computerscience', 'Algorithms');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX341', 'Dijkstra''s Algorithm', 'O((V+E) log V)', 'algorithms', 'computerscience', 'Algorithms');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX342', 'Bellman-Ford', 'O(VE)', 'algorithms', 'computerscience', 'Algorithms');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX343', 'Floyd-Warshall', 'O(V³)', 'algorithms', 'computerscience', 'Algorithms');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX344', 'Knapsack Problem', 'DP[n][W] = max(DP[n-1][W], DP[n-1][W-w[n]] + v[n])', 'algorithms', 'computerscience', 'Algorithms');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX345', 'Longest Common Subsequence', 'DP[i][j] = DP[i-1][j-1]+1 if match else max(DP[i-1][j], DP[i][j-1])', 'algorithms', 'computerscience', 'Algorithms');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX346', 'KMP Algorithm', 'O(n+m) string matching', 'algorithms', 'computerscience', 'Algorithms');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX347', 'RSA Encryption', 'C = Mᵉ mod n, M = Cᵈ mod n', 'algorithms', 'computerscience', 'Algorithms');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX348', 'P vs NP', 'P = {problems solvable in polynomial time}', 'complexity', 'computerscience', 'Complexity');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX349', 'NP-Completeness', 'NP-complete = NP ∩ NP-hard', 'complexity', 'computerscience', 'Complexity');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX350', 'Cook-Levin Theorem', 'SAT is NP-complete', 'complexity', 'computerscience', 'Complexity');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX351', 'Time Hierarchy Theorem', 'DTIME(f(n)) ⊊ DTIME(f(n)log²f(n))', 'complexity', 'computerscience', 'Complexity');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX352', 'Space Hierarchy Theorem', 'DSPACE(f(n)) ⊊ DSPACE(f(n)log f(n))', 'complexity', 'computerscience', 'Complexity');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX353', 'Linear Regression', 'y = wᵀx + b', 'ml', 'computerscience', 'Machine Learning');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX354', 'Logistic Regression', 'P(y=1|x) = 1/(1+e^{-wᵀx})', 'ml', 'computerscience', 'Machine Learning');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX355', 'SVM', 'max 1/||w|| s.t. yᵢ(wᵀxᵢ + b) ≥ 1', 'ml', 'computerscience', 'Machine Learning');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX356', 'Neural Network', 'a⁽ˡ⁾ = σ(W⁽ˡ⁾a⁽ˡ⁻¹⁾ + b⁽ˡ⁾)', 'ml', 'computerscience', 'Machine Learning');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX357', 'Backpropagation', 'δ⁽ˡ⁾ = (w⁽ˡ⁺¹⁾)ᵀδ⁽ˡ⁺¹⁾ ⊙ σ''(z⁽ˡ⁾)', 'ml', 'computerscience', 'Machine Learning');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX358', 'Gradient Descent', 'w ← w - η∇L(w)', 'ml', 'computerscience', 'Machine Learning');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX359', 'PCA', 'max Var(wᵀX) s.t. ||w||=1', 'ml', 'computerscience', 'Machine Learning');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX360', 'K-means', 'min Σ||x - μ||²', 'ml', 'computerscience', 'Machine Learning');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX361', 'Shannon Entropy', 'H(X) = -Σ p(x) log p(x)', 'info', 'computerscience', 'Information Theory');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX362', 'Mutual Information', 'I(X;Y) = H(X) - H(X|Y)', 'info', 'computerscience', 'Information Theory');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX363', 'KL Divergence', 'D_KL(P||Q) = Σ p(x) log(p(x)/q(x))', 'info', 'computerscience', 'Information Theory');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX364', 'Channel Capacity', 'C = max I(X;Y)', 'info', 'computerscience', 'Information Theory');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX365', 'Shannon-Hartley', 'C = B log₂(1 + S/N)', 'info', 'computerscience', 'Information Theory');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX366', 'Rate-Distortion', 'R(D) = min I(X;X̂) s.t. E[d(X,X̂)] ≤ D', 'info', 'computerscience', 'Information Theory');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX367', 'RSA', 'ed ≡ 1 (mod φ(n))', 'crypto', 'computerscience', 'Cryptography');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX368', 'AES', 'SubBytes, ShiftRows, MixColumns, AddRoundKey', 'crypto', 'computerscience', 'Cryptography');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX369', 'Diffie-Hellman', 'g^{ab} mod p', 'crypto', 'computerscience', 'Cryptography');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX370', 'ECC', 'y² = x³ + ax + b', 'crypto', 'computerscience', 'Cryptography');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX371', 'Digital Signature', 'Sign(priv, msg), Verify(pub, sig, msg)', 'crypto', 'computerscience', 'Cryptography');
INSERT INTO axioms (serial, name, equation, family, domain, category) VALUES ('AX372', 'Zero-Knowledge Proof', 'Prover convinces Verifier without revealing secret', 'crypto', 'computerscience', 'Cryptography');
